class Solution(object):
    def minOperations(self, nums):
        n = len(nums)
        ops = 0
        for i in range(n - 2):
            if nums[i] == 0:
                nums[i] ^= 1
                nums[i+1] ^= 1
                nums[i+2] ^= 1
                ops += 1
        if nums[n-2] == 0 or nums[n-1] == 0:
            return -1
        return ops
